SELECT model, capacity, next_maintenance_date
FROM aircrafts
ORDER BY next_maintenance_date ASC;

SELECT COUNT(*) AS num_airports_in_baltimore
FROM airports
WHERE city = 'Baltimore';

SELECT AVG(duration) AS average_delay_duration
FROM delays
WHERE duration > 0;

SELECT model, capacity, manufacturer
FROM aircrafts
WHERE capacity = (SELECT MAX(capacity) FROM aircrafts);

SELECT AVG(performance_metrics.on_time_performance) AS average_on_time_performance
FROM performance_metrics
INNER JOIN delays ON performance_metrics.flight_id = delays.flight_id;

SELECT AVG(average_delay) AS average_delay
FROM performance_metrics
WHERE on_time_performance >= 95.0;

SELECT model, MAX(capacity) AS max_capacity
FROM aircrafts
GROUP BY model;

SELECT delay_type, COUNT(*) AS total_delays
FROM delays
GROUP BY delay_type;

SELECT AVG(duration) AS average_delay_60_min_delays
FROM delays
WHERE duration > 60;

SELECT AVG(average_passenger_load) AS avg_passenger_load
FROM flight_routes
WHERE route_status = 'active';
